from prometheus_client import start_http_server, Gauge
import time
import psycopg2

# Define Prometheus metrics
db_connection_gauge = Gauge('db_connection_status', 'Database connection status', ['host', 'connection_string'])

def check_db_connection():
    # Database credentials
    db_config = {
        'username': 'your_username',
        'password': 'your_password',
        'host': 'your_host',
        'dbname': 'your_dbname'
    }
    
    # Connection string
    connection_string = f"dbname={db_config['dbname']} user={db_config['username']} password=**** host={db_config['host']}"

    try:
        # Attempt to connect to the database
        conn = psycopg2.connect(
            dbname=db_config['dbname'],
            user=db_config['username'],
            password=db_config['password'],
            host=db_config['host']
        )
        conn.close()
        # Update Prometheus metric
        db_connection_gauge.labels(host=db_config['host'], connection_string=connection_string).set(1)
    except Exception as e:
        # Update Prometheus metric
        db_connection_gauge.labels(host=db_config['host'], connection_string=connection_string).set(0)

if __name__ == '__main__':
    # Start Prometheus server
    start_http_server(8000)
    while True:
        check_db_connection()
        time.sleep(60)  # Check every 60 seconds